import pika
import time
import json
import threading

def publisher():
    connection = pNone
    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        channel = connection.channel()

        queue_name = 'task_queue'
        channel.queue_declare(queue=queue_name, durable=True)

        print("Publisher started. Sending task messages...")

        for i in range(1, 11):
            task = {
                'task_id': i,
                'description': f'Process data for item {i}',
                'timestamp': time.time()
            }
            message = json.dumps(task)
            channel.basic_publish(
                exchange='',
                routing_key=queue_name,
                body=message,
                properties=pika.BasicProperties(
                    delivery_mode=pika.spec.PERSISTENT_ONE
                )
            )
            print(f" [x] Sent '{message}'")
            time.sleep(1) # Simulate some work

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Publisher: Could not connect to RabbitMQ: {e}")
    except Exception as e:
        print(f"Publisher error: {e}")
    finally:
        if connection and connection.is_open:
            connection.close()
            print("Publisher connection closed.")

def consumer():
    connection = pNone
    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        channel = connection.channel()

        queue_name = 'task_queue'
        channel.queue_declare(queue=queue_name, durable=True)

        print('Consumer started. Waiting for messages. To exit press CTRL+C')

        def callback(ch, method, properties, body):
            task = json.loads(body)
            print(f" [x] Received '{task}'")
            # Simulate work
            print(f"     Processing task_id: {task['task_id']}...")
            time.sleep(2)
            print(f" [x] Done processing task_id: {task['task_id']}")
            ch.basic_ack(delivery_tag=method.delivery_tag)

        channel.basic_qos(prefetch_count=1) # Don't dispatch a new message to a worker until it has processed and acknowledged the previous one.
        channel.basic_consume(queue=queue_name, on_message_callback=callback)

        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Consumer: Could not connect to RabbitMQ: {e}")
    except KeyboardInterrupt:
        print("Consumer stopped by user.")
    except Exception as e:
        print(f"Consumer error: {e}")
    finally:
        if connection and connection.is_open:
            connection.close()
            print("Consumer connection closed.")

if __name__ == '__main__':
    # Start publisher and consumer in separate threads
    # In a real distributed system, these would typically be separate processes or even separate machines.
    # For demonstration purposes, we run them concurrently in threads.

    publisher_thread = threading.Thread(target=publisher)
    consumer_thread = threading.Thread(target=consumer)

    publisher_thread.start()
    consumer_thread.start()

    publisher_thread.join()
    consumer_thread.join()

    print("Application finished.")